func swarmClusterStatusClass(status string) string {
	switch status {
	case "active":
		return "px-2 py-0.5 text-xs rounded-full bg-green-900/40 text-green-400"
	case "initializing":
		return "px-2 py-0.5 text-xs rounded-full bg-blue-900/40 text-blue-400 animate-pulse"
	case "degraded":
		return "px-2 py-0.5 text-xs rounded-full bg-orange-900/40 text-orange-400"
	default:
		return "px-2 py-0.5 text-xs rounded-full bg-neutral-700 text-neutral-500"
	}
}

